script:
frappe.ui.form.on('Client Project Onboarding', {

    refresh: function(frm) {
        // Show Send Kickoff Email button
        if (!frm.is_new() && frm.doc.status === 'Kickoff Scheduled') {
            frm.add_custom_button('Send Kickoff Email', function() {
                send_kickoff_email(frm);
            });
        }
    },

    start_date: function(frm) {
        validate_start_date(frm);
    },

    status: function(frm) {
        if (frm.doc.status === 'Kickoff Scheduled') {
            if (!frm.doc.sow_attached) {
                frappe.msgprint({
                    title: 'SOW Required',
                    message: 'SOW must be attached before scheduling kickoff.',
                    indicator: 'red'
                });
                frm.set_value('status', 'Draft');
            }
        }
    },

    validate: function(frm) {
        // Validate start date
        if (frm.doc.start_date) {
            let today = frappe.datetime.get_today();
            if (frm.doc.start_date < today) {
                frappe.msgprint({
                    title: 'Invalid Start Date',
                    message: 'Start Date cannot be in the past.',
                    indicator: 'red'
                });
                frappe.validated = false;
            }
        }

        // Warn if no team members
        if (!frm.doc.team_members || frm.doc.team_members.length === 0) {
            frappe.msgprint({
                title: 'No Team Assigned',
                message: 'No team assigned. Are you sure you want to proceed?',
                indicator: 'orange'
            });
        }

        // Block if SOW not attached and status is Kickoff Scheduled
        if (frm.doc.status === 'Kickoff Scheduled' && !frm.doc.sow_attached) {
            frappe.msgprint({
                title: 'SOW Required',
                message: 'SOW must be attached before scheduling kickoff.',
                indicator: 'red'
            });
            frappe.validated = false;
        }
    }
});

function validate_start_date(frm) {
    if (frm.doc.start_date) {
        let today = frappe.datetime.get_today();
        if (frm.doc.start_date < today) {
            frappe.msgprint({
                title: 'Invalid Start Date',
                message: 'Start Date cannot be in the past.',
                indicator: 'red'
            });
            frm.set_value('start_date', '');
        }
    }
}

function send_kickoff_email(frm) {
    // Build team members list
    let team_list = '';
    if (frm.doc.team_members) {
        frm.doc.team_members.forEach(function(member) {
            team_list += '- ' + member.employee + ' (' + member.role + ')\n';
        });
    }

    let email_body = `Dear Team,

We are excited to announce the kickoff of project: ${frm.doc.project_name}

Client: ${frm.doc.client_name}
Project Type: ${frm.doc.project_type}
Start Date: ${frm.doc.start_date}
Project Manager: ${frm.doc.project_manager}
Tech Lead: ${frm.doc.tech_lead}

Team Members:
${team_list}

Please make sure to review the SOW and be ready for the kickoff meeting.

Best Regards,
${frm.doc.project_manager}`;

    frappe.prompt([
        {
            fieldname: 'email_body',
            fieldtype: 'Text Editor',
            label: 'Email Body',
            default: email_body
        },
        {
            fieldname: 'recipients',
            fieldtype: 'Data',
            label: 'Recipients (comma separated emails)',
        }
    ],
    function(values) {
        frappe.call({
            method: 'frappe.core.doctype.communication.email.make',
            args: {
                recipients: values.recipients,
                subject: 'Project Kickoff: ' + frm.doc.project_name,
                content: values.email_body,
                doctype: frm.doctype,
                name: frm.docname,
                send_email: 1
            },
            callback: function(r) {
                if (!r.exc) {
                    frappe.msgprint({
                        title: 'Success',
                        message: 'Kickoff email sent successfully!',
                        indicator: 'green'
                    });
                }
            }
        });
    },
    'Send Kickoff Email',
    'Send'
    );
}
